  return <div className="animate-in" style={{padding:24,maxWidth:1000}}><div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:18,flexWrap:'wrap',gap:10}}><div><h1 style={{fontFamily:'var(--fh)',fontSize:19,fontWeight:700}}>{i.teams_title}</h1><p style={{color:'var(--muted)',fontSize:13,marginTop:2}}>{filtered.length} · {filtered.filter(t=>t.paid).length} ✓</p></div><button className="btn btn-cyan" onClick={()=>setShowAdd(!showAdd)}>{i.btn_reg_team}</button></div><div style={{display:'flex',gap:6,marginBottom:14,flexWrap:'wrap'}}><button onClick={()=>setSelT('all')} style={{padding:'4px 12px',borderRadius:3,border:'1px solid',cursor:'pointer',fontFamily:'var(--fm)',fontSize:9,textTransform:'uppercase',background:selT==='all'?'var(--cyan)':'transparent',color:selT==='all'?'#000':'var(--muted)',borderColor:selT==='all'?'var(--cyan)':'var(--border)'}}>{i.all}</button>{tournaments.map(t=><button key={t.id} onClick={()=>setSelT(t.id)} style={{padding:'4px 12px',borderRadius:3,border:'1px solid',cursor:'pointer',fontFamily:'var(--fm)',fontSize:9,textTransform:'uppercase',background:selT===t.id?'var(--cyan)':'transparent',color:selT===t.id?'#000':'var(--muted)',borderColor:selT===t.id?'var(--cyan)':'var(--border)'}}>{t.name.split(' ').slice(0,2).join(' ')}</button>)}</div>{showAdd&&<div className="card" style={{marginBottom:14,borderColor:'var(--cyan)'}}><div className="g2" style={{marginBottom:11}}><div><label>{i.team_name}</label><input value={form.name} onChange={e=>setForm(f=>({...f,name:e.target.value}))} placeholder="Alpha Squad"/></div><div><label>{i.captain}</label><input value={form.captain} onChange={e=>setForm(f=>({...f,captain:e.target.value}))} placeholder="Name"/></div></div><div className="g3" style={{marginBottom:11}}><div><label>{i.contact}</label><input value={form.contact} onChange={e=>setForm(f=>({...f,contact:e.target.value}))} placeholder="08xx"/></div><div><label>{i.members}</label><select value={form.members} onChange={e=>setForm(f=>({...f,members:e.target.value}))}>{[1,2,3,4,5,6].map(n=><option key={n}>{n}</option>)}</select></div><div><label>{i.tournament}</label><select value={form.tournament_id} onChange={e=>setForm(f=>({...f,tournament_id:e.target.value}))}>{tournaments.map(t=><option key={t.id} value={t.id}>{t.name}</option>)}</select></div></div><div style={{display:'flex',alignItems:'center',gap:9,marginBottom:13}}><input type="checkbox" checked={form.paid} onChange={e=>setForm(f=>({...f,paid:e.target.checked}))} style={{width:14,height:14,accentColor:'var(--cyan)'}}/><span style={{fontSize:14}}>{i.paid_lbl}</span></div><div style={{display:'flex',gap:8}}><button className="btn btn-cyan" onClick={submit} disabled={saving}>{saving?<Spinner size={13} color="#000"/>:i.btn_reg2}</button><button className="btn btn-ghost" onClick={()=>setShowAdd(false)}>{i.btn_cancel}</button></div></div>}<div className="card" style={{padding:0,overflow:'hidden'}}><div style={{overflowX:'auto'}}><table style={{width:'100%',borderCollapse:'collapse',minWidth:500}}><thead><tr style={{borderBottom:'1px solid var(--border)'}}>{[i.team_name,i.captain,i.contact,i.members,i.tournament,'✓','⋯'].map(h=><th key={h} style={{padding:'10px 13px',textAlign:'left',fontFamily:'var(--fm)',fontSize:9,color:'var(--muted)',letterSpacing:1,textTransform:'uppercase',fontWeight:400}}>{h}</th>)}</tr></thead><tbody>{filtered.map((t,idx)=>{const tr=tournaments.find(x=>x.id===t.tournament_id);return <tr key={t.id} style={{borderBottom:'1px solid var(--border)',background:idx%2===0?'transparent':'rgba(255,255,255,0.01)'}}><td style={{padding:'10px 13px',fontWeight:600,fontSize:13}}>{t.name}</td><td style={{padding:'10px 13px',fontSize:12,color:'var(--muted)'}}>{t.captain}</td><td style={{padding:'10px 13px',fontFamily:'var(--fm)',fontSize:11,color:'var(--muted)'}}>{t.contact||'-'}</td><td style={{padding:'10px 13px',textAlign:'center',fontFamily:'var(--fm)'}}>{t.members}</td><td style={{padding:'10px 13px',fontSize:11,color:'var(--cyan)'}}>{tr?.name||'-'}</td><td style={{padding:'10px 13px'}}><button onClick={()=>updateTeam(t.id,{paid:!t.paid})} style={{background:'none',border:'none',cursor:'pointer',fontSize:16}}>{t.paid?'✅':'⬜'}</button></td><td style={{padding:'10px 13px'}}><button onClick={()=>deleteTeam(t.id,t.tournament_id)} style={{background:'rgba(255,45,85,0.1)',border:'1px solid rgba(255,45,85,0.25)',borderRadius:3,padding:'3px 9px',color:'var(--red)',cursor:'pointer',fontSize:10}}>✕</button></td></tr>})}</tbody></table>{filtered.length===0&&<div style={{textAlign:'center',padding:32,color:'var(--muted)'}}>{i.no_teams}</div>}</div></div></div>
