function Finance({tournaments,teams,lang}){
  const i=T[lang]||T.id;
  const rows=tournaments.map(t=>{const p=teams.filter(x=>x.tournament_id===t.id&&x.paid).length;const g=p*Number(t.entry);return{...t,paid:p,gross:g,commission:g*0.15}});
  const tG=rows.reduce((s,r)=>s+r.gross,0),tC=rows.reduce((s,r)=>s+r.commission,0);
  return <div className="animate-in" style={{padding:24,maxWidth:1000}}><div style={{marginBottom:18}}><h1 style={{fontFamily:'var(--fh)',fontSize:19,fontWeight:700}}>{i.finance_title}</h1></div><div className="g3" style={{marginBottom:18}}><StatCard icon="💵" label={i.total_entry} value={fmtRp(tG)} color="var(--cyan)"/><StatCard icon="🏦" label={i.comm_lbl} value={fmtRp(tC)} color="var(--orange)"/><StatCard icon="🎯" label={i.done} value={tournaments.filter(t=>t.status==='closed').length} color="var(--green)"/></div><div className="card" style={{padding:0,overflow:'hidden'}}><div style={{overflowX:'auto'}}><table style={{width:'100%',borderCollapse:'collapse',minWidth:480}}><thead><tr style={{borderBottom:'1px solid var(--border)'}}>{[i.tourn_title,i.teams_title,i.total_entry,i.comm_lbl,'Status'].map(h=><th key={h} style={{padding:'10px 13px',textAlign:'left',fontFamily:'var(--fm)',fontSize:9,color:'var(--muted)',letterSpacing:1,textTransform:'uppercase',fontWeight:400}}>{h}</th>)}</tr></thead><tbody>{rows.map((r,idx)=><tr key={r.id} style={{borderBottom:'1px solid var(--border)',background:idx%2===0?'transparent':'rgba(255,255,255,0.01)'}}><td style={{padding:'10px 13px',fontWeight:600,fontSize:13}}>{r.name}</td><td style={{padding:'10px 13px',textAlign:'center'}}>{r.paid}/{r.registered||0}</td><td style={{padding:'10px 13px',fontFamily:'var(--fm)',fontSize:12,color:'var(--cyan)'}}>{fmtRp(r.gross)}</td><td style={{padding:'10px 13px',fontFamily:'var(--fm)',fontSize:12,color:'var(--orange)'}}>{fmtRp(r.commission)}</td><td style={{padding:'10px 13px'}}><span className={`tag tag-${r.status}`}>{r.status}</span></td></tr>)}</tbody><tfoot><tr style={{borderTop:'2px solid var(--border)'}}><td colSpan={2} style={{padding:'10px 13px',fontFamily:'var(--fh)',fontSize:10,color:'var(--cyan)'}}>TOTAL</td><td style={{padding:'10px 13px',fontFamily:'var(--fm)',fontSize:12,fontWeight:700,color:'var(--cyan)'}}>{fmtRp(tG)}</td><td style={{padding:'10px 13px',fontFamily:'var(--fm)',fontSize:12,fontWeight:700,color:'var(--orange)'}}>{fmtRp(tC)}</td><td/></tr></tfoot></table></div></div></div>
}

function RevenuePage({tournaments,teams,toast,lang}){
  const i=T[lang]||T.id;
  const[showWd,setShowWd]=useState(false);const[wdAmt,setWdAmt]=useState('');const[wdH,setWdH]=useState([{id:'w1',date:'2026-05-28',amount:450000,status:'cair',method:'BCA 1234xxxx'}]);
  const rows=tournaments.map(t=>{const p=teams.filter(x=>x.tournament_id===t.id&&x.paid).length;const g=p*Number(t.entry);return{...t,comm:g*0.15,sp:t.status==='closed'?Number(t.prize)*0.08:0,pr:t.status!=='pending'?50000:0}});
  const tC=rows.reduce((s,r)=>s+r.comm,0),grand=rows.reduce((s,r)=>s+r.comm+r.sp+r.pr,0),totalWd=wdH.reduce((s,w)=>s+w.amount,0),saldo=grand-totalWd;
  const doWd=()=>{const a=Number(wdAmt);if(!a||a<10000){toast('Min Rp10.000','error');return;}if(a>saldo){toast('Saldo tidak cukup!','error');return;}setWdH(p=>[{id:uid(),date:new Date().toISOString().slice(0,10),amount:a,status:'proses',method:'BCA 1234xxxx'},...p]);toast(`${i.withdraw_btn} ${fmtRp(a)} ✓`,'success');setWdAmt('');setShowWd(false)};
  return <div className="animate-in" style={{padding:24,maxWidth:1000}}><div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:20,flexWrap:'wrap',gap:12}}><div><h1 style={{fontFamily:'var(--fh)',fontSize:19,fontWeight:700,color:'var(--cyan)'}}>{i.rev_title}</h1><p style={{color:'var(--muted)',fontSize:13,marginTop:2}}>{i.rev_sub}</p></div><button className="btn btn-orange" onClick={()=>setShowWd(true)}>{i.withdraw_btn}</button></div><div style={{background:'linear-gradient(135deg,rgba(0,229,255,0.1),rgba(255,107,0,0.08))',border:'1px solid rgba(0,229,255,0.3)',borderRadius:8,padding:22,marginBottom:18,position:'relative'}}><div style={{position:'absolute',top:10,right:12,fontSize:10,fontFamily:'var(--fm)',color:'var(--cyan)'}}><span className="live-dot"/>LIVE</div><div style={{fontFamily:'var(--fm)',fontSize:9,color:'var(--muted)',letterSpacing:2,marginBottom:6}}>{i.saldo}</div><div style={{fontFamily:'var(--fh)',fontSize:30,fontWeight:900,color:'var(--cyan)',marginBottom:3}}>{fmtRp(saldo)}</div><div style={{fontSize:12,color:'var(--muted)'}}>{i.income} <span style={{color:'var(--green)'}}>{fmtRp(grand)}</span> · {i.withdrawn} <span style={{color:'var(--orange)'}}>{fmtRp(totalWd)}</span></div></div><div className="g4" style={{marginBottom:18}}><StatCard icon="🎫" label={i.comm_lbl} value={fmtRp(tC)} color="var(--cyan)"/><StatCard icon="🏅" label="Sponsorship" value={fmtRp(rows.reduce((s,r)=>s+r.sp,0))} color="var(--orange)"/><StatCard icon="⭐" label="Premium" value={fmtRp(rows.reduce((s,r)=>s+r.pr,0))} color="var(--green)"/><StatCard icon="📊" label={i.tourn_title} value={tournaments.length} color="var(--yellow)"/></div><div className="card" style={{marginBottom:16}}><div style={{fontFamily:'var(--fh)',fontSize:11,marginBottom:14,color:'var(--cyan)',letterSpacing:1}}>{i.comm_per}</div>{rows.length===0&&<div style={{color:'var(--muted)',fontSize:13}}>{i.no_tourn_yet}</div>}{[...rows].sort((a,b)=>(b.comm+b.sp+b.pr)-(a.comm+a.sp+a.pr)).map((r,idx)=>{const total=r.comm+r.sp+r.pr;const mx=rows.reduce((m,x)=>Math.max(m,x.comm+x.sp+x.pr),1);return <div key={r.id} style={{marginBottom:12}}><div style={{display:'flex',justifyContent:'space-between',marginBottom:4,flexWrap:'wrap',gap:6}}><div style={{display:'flex',gap:8,alignItems:'center'}}><span style={{fontFamily:'var(--fm)',fontSize:10,color:idx===0?'var(--yellow)':'var(--muted)',width:14}}>#{idx+1}</span><div><div style={{fontSize:13,fontWeight:600}}>{r.name}</div></div></div><div style={{fontFamily:'var(--fm)',fontSize:12,color:'var(--cyan)'}}>{fmtRp(total)}</div></div><div className="pbar"><div className="pfill" style={{width:`${(total/mx)*100}%`,background:idx===0?'var(--yellow)':'var(--cyan)'}}/></div></div>})}</div>{showWd&&<div className="overlay" onClick={e=>{if(e.target===e.currentTarget)setShowWd(false)}}><div className="modal" style={{maxWidth:400}}><div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:18}}><div style={{fontFamily:'var(--fh)',fontSize:13,color:'var(--orange)',letterSpacing:1}}>{i.withdraw_title}</div><button onClick={()=>setShowWd(false)} style={{background:'none',border:'none',color:'var(--muted)',cursor:'pointer',fontSize:20}}>×</button></div><div style={{background:'var(--bg3)',borderRadius:4,padding:'12px 14px',marginBottom:14}}><div style={{fontFamily:'var(--fm)',fontSize:9,color:'var(--muted)',marginBottom:3}}>{i.saldo_lbl}</div><div style={{fontFamily:'var(--fh)',fontSize:22,color:'var(--cyan)',fontWeight:700}}>{fmtRp(saldo)}</div></div><div style={{marginBottom:13}}><label>{i.amount_lbl}</label><input type="number" value={wdAmt} onChange={e=>setWdAmt(e.target.value)} placeholder="Min Rp 10.000"/></div><div style={{marginBottom:18}}><label>{i.acc_lbl}</label><input value="BCA 1234xxxx" readOnly style={{color:'var(--muted)'}}/></div><div style={{display:'flex',gap:9}}><button className="btn btn-orange btn-full" onClick={doWd}>{i.btn_wd}</button><button className="btn btn-ghost" onClick={()=>setShowWd(false)}>{i.btn_cancel}</button></div></div></div>}</div>
}

function BracketView({tournaments,teams,lang}){
  const i=T[lang]||T.id;
  const[selT,setSelT]=useState(tournaments[0]?.id||'');const t=tournaments.find(x=>x.id===selT);const tTeams=teams.filter(x=>x.tournament_id===selT);const pairs=[];
  for(let idx=0;idx<Math.min(tTeams.length,8);idx+=2)pairs.push({a:tTeams[idx],b:tTeams[idx+1],w:Math.random()>0.5?tTeams[idx]?.id:tTeams[idx+1]?.id});
  return <div className="animate-in" style={{padding:24,maxWidth:1000}}><div style={{marginBottom:18}}><h1 style={{fontFamily:'var(--fh)',fontSize:19,fontWeight:700}}>{i.nav[5]}</h1></div><div style={{display:'flex',gap:6,marginBottom:16,flexWrap:'wrap'}}>{tournaments.map(x=><button key={x.id} onClick={()=>setSelT(x.id)} style={{padding:'6px 14px',borderRadius:4,cursor:'pointer',fontSize:12,fontWeight:500,background:selT===x.id?'var(--cyan)':'var(--panel)',color:selT===x.id?'#000':'var(--text)',border:`1px solid ${selT===x.id?'var(--cyan)':'var(--border)'}`,transition:'all 0.15s'}}>{x.name}</button>)}</div>{t&&<><div className="card" style={{marginBottom:16}}><div style={{display:'flex',justifyContent:'space-between',flexWrap:'wrap',gap:12}}><div><div style={{fontFamily:'var(--fh)',fontSize:15,fontWeight:700,color:'var(--cyan)'}}>{t.name}</div><div style={{fontSize:12,color:'var(--muted)',marginTop:3}}>{t.game} · {t.format}</div></div><div><div style={{fontFamily:'var(--fh)',fontSize:18,color:'var(--yellow)'}}>{fmtRp(t.prize)}</div></div></div></div>{tTeams.length<2?<div className="card" style={{textAlign:'center',padding:40,color:'var(--muted)'}}><div style={{fontSize:34,marginBottom:10}}>📊</div><div style={{fontFamily:'var(--fh)',fontSize:12}}>MIN. 2 TEAMS</div></div>:<div style={{display:'flex',gap:32,overflowX:'auto',paddingBottom:14,alignItems:'flex-start'}}><div style={{display:'flex',flexDirection:'column',gap:18,flexShrink:0}}>{pairs.map((p,idx)=><div key={idx}><div style={{fontSize:9,fontFamily:'var(--fm)',color:'var(--muted)',marginBottom:4}}>MATCH {idx+1}</div><div className="b-match"><div className={`b-team ${p.w===p.a?.id?'winner':'loser'}`}><span>{p.a?.name||'BYE'}</span>{p.w===p.a?.id&&<span>🏆</span>}</div><div className={`b-team ${p.w===p.b?.id?'winner':'loser'}`}><span>{p.b?.name||'BYE'}</span>{p.w===p.b?.id&&<span>🏆</span>}</div></div></div>)}</div><div style={{display:'flex',flexDirection:'column',justifyContent:'center',flexShrink:0,paddingTop:60}}><div style={{fontFamily:'var(--fm)',fontSize:9,color:'var(--yellow)',marginBottom:4}}>🏆 GRAND FINAL</div><div className="b-match" style={{border:'1px solid rgba(255,215,0,0.3)'}}><div className="b-team" style={{color:'var(--muted)'}}><span>TBD</span></div><div className="b-team" style={{color:'var(--muted)'}}><span>TBD</span></div></div><div style={{textAlign:'center',marginTop:8,fontSize:12,fontFamily:'var(--fh)',color:'var(--yellow)'}}>{fmtRp(t.prize)}</div></div></div>}</>}</div>
}

function Settings({user,lang}){
  const i=T[lang]||T.id;
  const name=user?.user_metadata?.organizer_name||user?.email?.split('@')[0]||'Organizer';
  const BANK_KEY='arenagg_bank_info';
  const loadBank=()=>{try{return JSON.parse(localStorage.getItem(BANK_KEY)||'{}')}catch(e){return{}}};
  const[bank,setBank]=useState(loadBank);const[saved,setSaved]=useState(false);
  const setB=k=>e=>setBank(b=>({...b,[k]:e.target.value}));
  const saveBank=()=>{localStorage.setItem(BANK_KEY,JSON.stringify(bank));setSaved(true);setTimeout(()=>setSaved(false),2000)};
  const BANKS=['BCA','BRI','BNI','Mandiri','BSI','DANA','OVO','GoPay','ShopeePay','SeaBank'];
  return <div className="animate-in" style={{padding:24,maxWidth:600}}><h1 style={{fontFamily:'var(--fh)',fontSize:19,fontWeight:700,marginBottom:18}}>{i.settings_title}</h1><div className="card" style={{marginBottom:14}}><div style={{fontFamily:'var(--fm)',fontSize:9,color:'var(--cyan)',marginBottom:14,letterSpacing:2}}>{i.account}</div><div style={{display:'flex',gap:14,alignItems:'center'}}><div style={{width:44,height:44,borderRadius:'50%',background:'linear-gradient(135deg,var(--cyan),var(--orange))',display:'flex',alignItems:'center',justifyContent:'center',fontWeight:700,fontSize:18,color:'#000'}}>{name[0].toUpperCase()}</div><div><div style={{fontWeight:700,fontSize:15}}>{name}</div><div style={{fontSize:12,color:'var(--muted)',marginTop:2}}>{user?.email}</div><div style={{fontSize:11,color:'var(--green)',marginTop:4}}>{i.connected}</div></div></div></div><div className="card" style={{marginBottom:14,borderColor:'rgba(255,215,0,0.3)'}}><div style={{fontFamily:'var(--fm)',fontSize:9,color:'var(--yellow)',marginBottom:14,letterSpacing:2}}>{i.bank_title}</div><div style={{fontSize:12,color:'var(--muted)',marginBottom:14,lineHeight:1.7}}>{i.bank_desc}</div><div style={{marginBottom:12}}><label>{i.bank_name}</label><select value={bank.bankName||''} onChange={setB('bankName')}><option value=''>{i.select_bank}</option>{BANKS.map(b=><option key={b}>{b}</option>)}</select></div><div style={{marginBottom:12}}><label>{i.acc_num}</label><input value={bank.accNumber||''} onChange={setB('accNumber')} placeholder="1234567890"/></div><div style={{marginBottom:12}}><label>{i.acc_owner}</label><input value={bank.accName||''} onChange={setB('accName')} placeholder="ARENAGG ORG"/></div><div style={{marginBottom:18}}><label>{i.wa_confirm}</label><input value={bank.waNumber||''} onChange={setB('waNumber')} placeholder="08xxxxxxxxxx" type="tel"/></div>{bank.bankName&&bank.accNumber&&<div style={{background:'rgba(0,229,255,0.07)',border:'1px solid rgba(0,229,255,0.2)',borderRadius:5,padding:'12px 14px',marginBottom:14}}><div style={{fontFamily:'var(--fm)',fontSize:9,color:'var(--cyan)',marginBottom:8,letterSpacing:1}}>{i.preview_lbl}</div><div style={{fontSize:14,lineHeight:2}}><div>🏦 <b>{bank.bankName}</b></div><div>💳 <b style={{color:'var(--cyan)',fontFamily:'var(--fm)',fontSize:13}}>{bank.accNumber}</b></div><div>👤 {bank.accName}</div>{bank.waNumber&&<div>📱 WA: <b>{bank.waNumber}</b></div>}</div></div>}<button className="btn btn-cyan" onClick={saveBank}>{saved?i.saved:i.btn_save_bank}</button></div><div className="card"><div style={{fontFamily:'var(--fm)',fontSize:9,color:'var(--yellow)',marginBottom:12,letterSpacing:2}}>{i.expansion}</div>{[{flag:'🇮🇩',country:'Indonesia',status:'active',note:'Pasar utama'},{flag:'🇵🇭',country:'Philippines',status:'soon',note:'Q3 2026'},{flag:'🇻🇳',country:'Vietnam',status:'soon',note:'Q4 2026'},{flag:'🇹🇭',country:'Thailand',status:'soon',note:'2027'}].map(c=><div key={c.country} style={{display:'flex',alignItems:'center',justifyContent:'space-between',padding:'9px 12px',background:'var(--bg3)',borderRadius:4,marginBottom:7}}><div style={{display:'flex',alignItems:'center',gap:9}}><span style={{fontSize:18}}>{c.flag}</span><div><div style={{fontWeight:600,fontSize:13}}>{c.country}</div><div style={{fontSize:11,color:'var(--muted)'}}>{c.note}</div></div></div><span className={`tag ${c.status==='active'?'tag-active':'tag-pending'}`}>{c.status==='active'?'AKTIF':'SEGERA'}</span></div>)}</div></div>
}

export default function App(){
  const[user,setUser]=useState(null);const[loading,setLoading]=useState(true);const[page,setPage]=useState('dashboard');const[editT,setEditT]=useState(null);const[pubTid,setPubTid]=useState(null);const[toasts,setToasts]=useState([]);
  const[lang,setLangState]=useState(getLang());
  const setLangFn=l=>{setLangState(l);setLang(l)};
  const toast=useCallback((msg,type='info')=>{const id=uid();setToasts(p=>[...p,{id,msg,type}]);setTimeout(()=>setToasts(p=>p.filter(t=>t.id!==id)),3200)},[]);
  useEffect(()=>{const parse=()=>{const m=window.location.hash.match(/^#\/daftar\/(.+)$/);setPubTid(m?m[1]:null)};parse();window.addEventListener('hashchange',parse);return()=>window.removeEventListener('hashchange',parse)},[]);
  useEffect(()=>{supabase.auth.getSession().then(({data})=>{setUser(data.session?.user||null);setLoading(false)});const{data:{subscription}}=supabase.auth.onAuthStateChange((_,session)=>setUser(session?.user||null));return()=>subscription.unsubscribe()},[]);
  const{tournaments,teams,loading:dataLoading,addT,updateT,deleteT,addTeam,updateTeam,deleteTeam}=useData(user?.id,toast);
  useEffect(()=>{if(page!=='create')setEditT(null)},[page]);
  const logout=async()=>{await supabase.auth.signOut();setUser(null)};
  if(pubTid!==null)return <><PublicPage tid={pubTid} onBack={()=>{window.location.hash=''}} toast={toast}/><Toasts list={toasts}/></>;
  if(loading)return <div style={{minHeight:'100vh',background:'var(--bg)',display:'flex',alignItems:'center',justifyContent:'center'}}><div style={{textAlign:'center'}}><div style={{fontFamily:'var(--fh)',fontSize:20,color:'var(--cyan)',letterSpacing:3,animation:'glow-pulse 2s infinite',marginBottom:16}}>⚔ ARENAGG</div><Spinner size={28} color="var(--cyan)"/></div></div>;
  if(!user)return <><AuthPage onLogin={u=>setUser(u)} lang={lang}/><Toasts list={toasts}/></>;
  const props={tournaments,teams,loading:dataLoading,setPage,editData:editT,setEditT,toast,user,addT,updateT,deleteT,addTeam,updateTeam,deleteTeam,onPreview:id=>{window.location.hash=`/daftar/${id}`},lang};
  return <div style={{display:'flex',minHeight:'100vh',background:'var(--bg)'}}><Sidebar page={page} setPage={setPage} user={user} onLogout={logout} lang={lang} setLangFn={setLangFn}/><main style={{flex:1,overflowY:'auto',overflowX:'hidden'}}>{page==='dashboard'&&<Dashboard {...props}/>}{page==='revenue'&&<RevenuePage {...props}/>}{page==='tournaments'&&<TournamentList {...props}/>}{page==='create'&&<CreateTournament addT={addT} updateT={updateT} editData={editT} setEditT={setEditT} toast={toast} lang={lang}/>}{page==='teams'&&<TeamsView {...props}/>}{page==='bracket'&&<BracketView {...props}/>}{page==='finance'&&<Finance {...props}/>}{page==='settings'&&<Settings user={user} lang={lang}/>}</main><BottomNav page={page} setPage={setPage} lang={lang}/><Toasts list={toasts}/></div>
}
